import{_ as t,o as n,c as i,ag as r}from"./chunks/framework.DXGyWiRo.js";const a="/images/schrift020.jpg",s="/images/schrift021.jpg",o="/images/schrift022.jpg",h="/images/schrift023.jpg",c="/images/schrift024.jpg",l="/images/schrift025.jpg",_=JSON.parse('{"title":"Schriftübung 10","description":"","frontmatter":{},"headers":[],"relativePath":"lektionen/schrift10.md","filePath":"lektionen/schrift10.md"}'),u={name:"lektionen/schrift10.md"};function p(d,e,g,m,b,f){return n(),i("div",null,[...e[0]||(e[0]=[r('<div class="info custom-block github-alert"><p class="custom-block-title">Zitierweise &amp; Rechte</p><p>Dieses Kapitel ist Teil des Sanskritkurses. Details zum Copyright und zur Zitierweise der Ursprungsfassung siehe: <a href="/impressum">Impressum &amp; Copyright</a></p></div><h1 id="schriftubung-10" tabindex="-1">Schriftübung 10 <a class="header-anchor" href="#schriftubung-10" aria-label="Permalink to &quot;Schriftübung 10&quot;">​</a></h1><h3 id="zweite-regel-zur-bildung-von-konsonantenligaturen" tabindex="-1">Zweite Regel zur Bildung von Konsonantenligaturen <a class="header-anchor" href="#zweite-regel-zur-bildung-von-konsonantenligaturen" aria-label="Permalink to &quot;Zweite Regel zur Bildung von Konsonantenligaturen&quot;">​</a></h3><p>[Erste Regel siehe in <a href="./schrift08">Schriftübung 8</a>]</p><p>Wenn der erste der zu verbindenden Konsonanten nicht mit einem senkrechten Strich abschließt, dann wird der folgende Konsonant mit Verlust seines wagrechten Strichs unter den ersten Konsonanten gesetzt.</p><p>Ausnahmen: Sind म् bzw. य् das zweite Glied der Ligatur, so werden sie verkürzt hinter das erste Zeichen geschrieben:</p><blockquote><p>क्म kma, ङ्म ṅma, द्म dma, ह्म hma, क्य kya, छ्य chya, द्य dya, ह्य hya</p></blockquote><p>Merke:</p><blockquote><p>क्त kta, त्त tta, द्द dda, द्ध ddha, द्न dna, द्भ dbha, ह्न hna, द्व dva, ह्व hva</p><p>क्ष kṣa, ज्ञ jña, ण्ण ṇṇa, ह्ण hṇa</p></blockquote><p><img src="'+a+'" alt=""></p><p>Beispiele (Ausnahmen sind unterstrichen):</p><p><img src="'+s+'" alt=""></p><p><img src="'+o+'" alt=""></p><h3 id="ubung" tabindex="-1">Übung <a class="header-anchor" href="#ubung" aria-label="Permalink to &quot;Übung&quot;">​</a></h3><p>Schreiben Sie alle oben angeführten Ligaturen</p><h3 id="verzeichnis-der-gebauchlichsten-ligaturen-in-der-schrifttype-von-kielhorns-grammatik" tabindex="-1">Verzeichnis der gebäuchlichsten Ligaturen in der Schrifttype von Kielhorns Grammatik <a class="header-anchor" href="#verzeichnis-der-gebauchlichsten-ligaturen-in-der-schrifttype-von-kielhorns-grammatik" aria-label="Permalink to &quot;Verzeichnis der gebäuchlichsten Ligaturen in der Schrifttype von Kielhorns Grammatik&quot;">​</a></h3><p><img src="'+h+'" alt=""></p><p><img src="'+c+'" alt=""></p><p><img src="'+l+'" alt=""></p><h3 id="ubung-1" tabindex="-1">Übung <a class="header-anchor" href="#ubung-1" aria-label="Permalink to &quot;Übung&quot;">​</a></h3><p>Lesen und transliterieren Sie:</p><p>वाक्चल वाक्छलम् पृथग्जनः वाक्टीका वाग्झटिति षड्कोण षट्खेटकम् वाग्डम्बरः खङ्गः द्विड्घोरा भक्तिः उत्कट उक्थम् उत्खात हृद्गत सद्गुण दग्ध उद्घाटकः वाक्पटु वाक्फलम् ककुप्खालु पृथग्भावः कुकुब्गुरुः कुकुब्घोरा षट्चरणः षट्छविः षड्जः अप्चरः ककुप्छविः कुब्ज षड्देवाः षड्धा षट्पति दुप्टीका षट्फण षड्बाहु ककुपठक्कुरः अब्डिम्भ लब्ध भगवद्गीता संयुक्त अद्भूत बुद्धियुक्त सच्छब्दः अङ्क शङ्ख लिङ्गम् सञ्जयः सङ्घ कण्ठः पण्डितः अन्तः पन्थक सुन्दर इन्धः कम्पन गुम्फति सम्बन्धः आरम्भः पङ्क्तिः याच्ञा ज्ञानम् रत्नम् पाप्मन् तज्ज्ञेय सञ्ज्ञा संज्ञा विशेषज्ञः जिज्ञासुः ऋक्ण रुग्ण ग्र्भ्णाति शक्णोति अग्निः विघ्न पद्मा ध्मातम् दध्मौ दिङ्नाग वाङ्मय षण्मास म्नात क्वचित्त् पक्वान्न आख्यो ऋग्वेदः ह्वे विह्वल तत्त्व ईश्वरः अन्वित दृड्ढम् श्र्ण्वन् आश्चर्यम् श्वस्रु श्मस्रु सृष्टिः दंष्ट्र दृष्ट्वा स्खलित स्तब्ध क्षेत्रज्ञ वत्सः स्निग्धः श्रेष्ठत्वम् श्च्युत अक्षर लिप्ति दृप्ति मुक्ति मुञ्चति</p>',22)])])}const v=t(u,[["render",p]]);export{_ as __pageData,v as default};
